mapper.select:
SELECT count(1) FROM user_notice_target t LEFT JOIN user_notice_config c ON t.notice_id = c.id WHERE t.user_id = #{vo.userId}
AND t.notice_type = 2
AND t.notice_type in (1,3,4)
AND t.platform = 1 AND t.delete_state = 1 AND t.read_state=0 and t.revoke_state=1 AND (c.terminal IS NULL OR c.terminal = '' OR FIND_IN_SET(#{vo.deviceTerminal}, c.terminal));

SELECT c.id AS noticeId, 0 AS targetId, c.notice_type, c.notice_title, c.message_content, c.target_type, c.status, c.created_time AS createdTime, 0 AS readState FROM user_notice_config c, user_info u WHERE c.target_type = 1 AND c.status = 0 AND u.user_account = #{vo.userAccount} AND NOT EXISTS ( SELECT t.notice_id FROM user_notice_target t WHERE t.notice_id = c.id AND t.user_account = #{vo.userAccount} ) AND c.notice_type = #{vo.noticeType}
AND c.created_time >= u.register_time
and c.carousel_start_time <= #{vo.currentTime} and c.carousel_end_time >= #{vo.currentTime}
UNION
SELECT c.id AS noticeId, 0 AS targetId, c.notice_type, c.notice_title, c.message_content, c.target_type, c.status, c.created_time AS createdTime, 0 AS readState FROM user_notice_config c, user_info u WHERE c.target_type = 3 AND c.status = 0 AND u.user_account = #{vo.userAccount} AND NOT EXISTS ( SELECT t.notice_id FROM user_notice_target t WHERE t.notice_id = c.id AND t.user_account = #{vo.userAccount} ) AND c.notice_type = #{vo.noticeType} AND FIND_IN_SET(#{vo.deviceTerminal}, c.send_object)
AND c.created_time >= u.register_time
and c.carousel_start_time <= #{vo.currentTime} and c.carousel_end_time >= #{vo.currentTime}

select
count(c.id)

from user_notice_config c, user_info u

where c.target_type = 1 and c.status=0 and u.user_account = #{userAccount}
and not exists (
select t.notice_id
from user_notice_target t
where t.notice_id = c.id and t.user_account = #{userAccount}
)
and c.notice_type = #{noticeType}



    and c.created_time  >=  u.register_time


    and c.carousel_start_time   <=  #{currentTime}
    and c.carousel_end_time   >=  #{currentTime}

select
count(c2.id)

from user_notice_target t2
left join user_notice_config c2 on c2.id = t2.notice_id

where t2.user_account = #{userAccount} and t2.revoke_state = 1 and t2.read_state = 0
and c2.notice_type = #{noticeType}

and t2.delete_state=1

    and c2.carousel_start_time   <=  #{currentTime}
    and c2.carousel_end_time   >=  #{currentTime}

SELECT sum( total_count ) AS total_count FROM ( SELECT count( c.id ) AS total_count FROM user_notice_config c, user_info u WHERE c.target_type = 1 AND c.STATUS = 0 AND u.user_account = #{userAccount} AND NOT EXISTS ( SELECT t.notice_id FROM user_notice_target t WHERE t.notice_id = c.id AND t.user_account = #{userAccount} ) AND c.notice_type = #{noticeType}
and c.created_time >= u.register_time
and c.carousel_start_time <= #{currentTime} and c.carousel_end_time >= #{currentTime}
UNION ALL
SELECT count( c2.id ) AS total_count FROM user_notice_target t2 LEFT JOIN user_notice_config c2 ON c2.id = t2.notice_id WHERE t2.user_account = #{userAccount} AND t2.revoke_state = 1 AND t2.read_state = 0 AND c2.notice_type = #{noticeType} AND t2.delete_state = 1
and c2.carousel_start_time <= #{currentTime} and c2.carousel_end_time >= #{currentTime}
UNION ALL
SELECT count( c.id ) AS total_count FROM user_notice_config c, user_info u WHERE c.target_type = 3 AND c.STATUS = 0 AND u.user_account = #{userAccount} AND NOT EXISTS ( SELECT t.notice_id FROM user_notice_target t WHERE t.notice_id = c.id AND t.user_account = #{userAccount} ) AND c.notice_type = #{noticeType} AND find_in_set(#{deviceTerminal}, c.send_object )
and c.created_time >= u.register_time
and c.carousel_start_time <= #{currentTime} and c.carousel_end_time >= #{currentTime}
) AS totalQuery

SELECT max(sort) AS total_count
FROM user_notice_config
where site_code = #{siteCode}
